import React, { useState } from 'react';
import styles from './EyewearEditSection.module.css';

const eyewearProducts = [
  {
    id: 1,
    name: 'EFFECTOR × RECTO FRAME 01 (BLACK)',
    price: '450,000 KRW',
    bg: '#dddad3',
    lensColor: 'rgba(60,60,60,0.35)',
    frameColor: '#2a2a2a',
  },
  {
    id: 2,
    name: 'EFFECTOR × RECTO FRAME 02 (BROWN)',
    price: '450,000 KRW',
    bg: '#e0dbd2',
    lensColor: 'rgba(139,100,55,0.3)',
    frameColor: '#7a5530',
  },
  {
    id: 3,
    name: 'EFFECTOR × RECTO FRAME 03 (GREY)',
    price: '450,000 KRW',
    bg: '#d8d5ce',
    lensColor: 'rgba(100,100,100,0.25)',
    frameColor: '#888',
  },
];

function EyewearCard({ product }) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      className={styles.card}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{ background: product.bg }}
    >
      {/* Eyewear illustration */}
      <div className={styles.eyewearWrap}>
        <div className={styles.frame} style={{ borderColor: product.frameColor }}>
          <div
            className={styles.lens}
            style={{ background: product.lensColor, borderColor: product.frameColor }}
          />
          <div className={styles.bridge} style={{ background: product.frameColor }} />
          <div
            className={styles.lens}
            style={{ background: product.lensColor, borderColor: product.frameColor }}
          />
        </div>
      </div>

      {/* Hover overlay */}
      <div className={`${styles.hoverOverlay} ${hovered ? styles.hoverVisible : ''}`}>
        <p className={styles.hoverName}>{product.name}</p>
        <p className={styles.hoverPrice}>{product.price}</p>
      </div>
    </div>
  );
}

function EyewearEditSection() {
  return (
    <section className={styles.section}>
      <div className={styles.sectionHeader}>
        <h2 className={styles.sectionTitle}>THE EDIT</h2>
        <a href="#!" className={styles.viewAll}>view all</a>
      </div>

      <div className={styles.grid}>
        {eyewearProducts.map((product) => (
          <EyewearCard key={product.id} product={product} />
        ))}
      </div>

    </section>
  );
}

export default EyewearEditSection;
